                expect(value).toBe(1);
            });
        })
        .then(function () {
            return queue.get()
            .then(function (value) {
                expect(value).toBe(2);
            });
        })
        .then(function () {
            return queue.get()
            .then(function (value) {
                expect(value).toBe(3);
            });
        })

    });

